import { Component, OnInit, ViewChild, ElementRef, AfterViewInit } from '@angular/core';
import { ActivatedRoute } from '@angular/router';
import { ProjectService } from '../../services/project.service';
import { AnnotationService } from '../../services/annotation.service';
import { AnalyticsService } from '../../services/analytics.service';
import { CanvasDrawingService } from '../../services/canvas-drawing.service';

interface AnnotationObject {
  id: string;
  type: 'rect' | 'polygon' | 'point' | 'polyline' | 'mask';
  label: string;
  points: Array<{x: number, y: number}>;
  color: string;
  confidence?: number;
  attributes?: {[key: string]: string | number | boolean};
  occluded?: boolean;
  rotation?: number;
}

interface DrawingState {
  isDrawing: boolean;
  startX: number;
  startY: number;
  currentPoints: Array<{x: number, y: number}>;
  previewPath?: Path2D;
}

@Component({
  selector: 'app-annotation',
  templateUrl: './annotation.component.html',
  styleUrls: ['./annotation.component.css']
})
export class AnnotationComponent implements OnInit {
  @ViewChild('canvas', { static: false }) canvasRef!: ElementRef<HTMLCanvasElement>;
  @ViewChild('fileInput', { static: false }) fileInput!: ElementRef<HTMLInputElement>;

  // Project state
  project: any;
  currentFileIndex = 0;
  files: File[] = [];
  currentImage: HTMLImageElement | null = null;

  // Annotation state
  annotations: AnnotationObject[] = [];
  selectedAnnotationId: string | null = null;
  selectedTool: 'select' | 'rect' | 'polygon' | 'point' | 'brush' | 'eraser' | 'polyline' = 'rect';
  selectedLabel: string | null = null;
  drawingState: DrawingState = {
    isDrawing: false,
    startX: 0,
    startY: 0,
    currentPoints: []
  };

  // Canvas & rendering
  canvas!: HTMLCanvasElement;
  ctx!: CanvasRenderingContext2D;
  zoomLevel = 1;
  panX = 0;
  panY = 0;

  // UI state
  showAttributesPanel = false;
  showExportPanel = false;
  showQualityFilter = false;
  brushSize = 5;
  brushOpacity = 1;
  gridEnabled = false;
  snapToGrid = false;

  // History for undo/redo
  history: AnnotationObject[][] = [];
  historyIndex = -1;

  // Labels and colors
  labels: {name: string, color: string, attributes?: string[]}[] = [];
  labelColors = [
    '#FF6B6B', '#4ECDC4', '#45B7D1', '#FFA07A', '#98D8C8',
    '#F7DC6F', '#BB8FCE', '#85C1E2', '#F8B88B', '#A3E4D7'
  ];

  constructor(
    private route: ActivatedRoute,
    private projectService: ProjectService,
    private annotationService: AnnotationService,
    private analyticsService: AnalyticsService,
    private drawingService: CanvasDrawingService
  ) {}

  ngOnInit(): void {
    const projectId = this.route.snapshot.paramMap.get('id');
    if (projectId) {
      this.loadProject(projectId);
    }
  }

  ngAfterViewInit(): void {
    this.canvas = this.canvasRef.nativeElement;
    this.ctx = this.canvas.getContext('2d')!;
    this.setupCanvasEventListeners();
    this.setupKeyboardShortcuts();
  }

  loadProject(projectId: string): void {
    this.projectService.getProject(projectId).subscribe((project) => {
      this.project = project;
      this.initializeLabels(project.labelSet);
    });
  }

  initializeLabels(labelSet: string[]): void {
    this.labels = labelSet.map((label, idx) => ({
      name: label,
      color: this.labelColors[idx % this.labelColors.length],
      attributes: []
    }));
    if (this.labels.length > 0) {
      this.selectedLabel = this.labels[0].name;
    }
  }

  // ===== Canvas Setup & Events =====
  setupCanvasEventListeners(): void {
    this.canvas.addEventListener('mousedown', (e) => this.onCanvasMouseDown(e));
    this.canvas.addEventListener('mousemove', (e) => this.onCanvasMouseMove(e));
    this.canvas.addEventListener('mouseup', (e) => this.onCanvasMouseUp(e));
    this.canvas.addEventListener('wheel', (e) => this.onCanvasWheel(e), false);
    this.canvas.addEventListener('contextmenu', (e) => e.preventDefault());
    this.canvas.addEventListener('dblclick', (e) => this.onCanvasDoubleClick(e));
  }

  setupKeyboardShortcuts(): void {
    document.addEventListener('keydown', (e) => {
      if (e.key === 'Escape') this.cancelDrawing();
      if (e.key === 'r') this.setTool('rect');
      if (e.key === 'p') this.setTool('polygon');
      if (e.key === 'd') this.setTool('point');
      if (e.key === 'b') this.setTool('brush');
      if (e.key === 'e') this.setTool('eraser');
      if (e.key === 'l') this.setTool('polyline');
      if (e.key === 's') this.setTool('select');
      if (e.key === 'Delete' && this.selectedAnnotationId) this.deleteAnnotation(this.selectedAnnotationId);
      if (e.ctrlKey && e.key === 'z') this.undo();
      if (e.ctrlKey && e.key === 'y') this.redo();
      if (e.key === 'g') this.gridEnabled = !this.gridEnabled;
      if (e.key === 't') this.snapToGrid = !this.snapToGrid;
    });
  }

  private getCanvasCoords(event: MouseEvent): {x: number, y: number} {
    const rect = this.canvas.getBoundingClientRect();
    return {
      x: (event.clientX - rect.left - this.panX) / this.zoomLevel,
      y: (event.clientY - rect.top - this.panY) / this.zoomLevel
    };
  }

  onCanvasMouseDown(event: MouseEvent): void {
    if (!this.currentImage) return;

    const {x, y} = this.getCanvasCoords(event);

    if (this.selectedTool === 'select') {
      this.selectAnnotationAtPoint(x, y);
      return;
    }

    this.drawingState.isDrawing = true;
    this.drawingState.startX = x;
    this.drawingState.startY = y;
    this.drawingState.currentPoints = [{x, y}];
  }

  onCanvasMouseMove(event: MouseEvent): void {
    if (!this.currentImage) return;

    const {x, y} = this.getCanvasCoords(event);

    if (!this.drawingState.isDrawing) {
      this.render();
      return;
    }

    // Live preview during drawing
    if (this.selectedTool === 'rect') {
      this.render();
      this.drawRectPreview(this.drawingState.startX, this.drawingState.startY, x, y);
    } else if (this.selectedTool === 'polygon' || this.selectedTool === 'polyline') {
      this.render();
      this.drawPolygonPreview(this.drawingState.currentPoints, x, y);
    } else if (this.selectedTool === 'brush') {
      this.drawBrush(x, y);
    } else if (this.selectedTool === 'eraser') {
      this.drawEraser(x, y);
    }
  }

  onCanvasMouseUp(event: MouseEvent): void {
    if (!this.drawingState.isDrawing) return;

    const {x, y} = this.getCanvasCoords(event);

    if (this.selectedTool === 'rect') {
      this.finalizeRect(this.drawingState.startX, this.drawingState.startY, x, y);
      this.drawingState.isDrawing = false;
    } else if (this.selectedTool === 'point') {
      this.addPoint(x, y);
      this.drawingState.isDrawing = false;
    } else if (this.selectedTool === 'polygon' || this.selectedTool === 'polyline') {
      // Polygon continues until double-click
    }

    this.render();
  }

  onCanvasWheel(event: WheelEvent): void {
    event.preventDefault();
    const delta = event.deltaY > 0 ? 0.9 : 1.1;
    const newZoom = this.zoomLevel * delta;
    this.zoomLevel = Math.max(0.1, Math.min(5, newZoom));
    this.render();
  }

  onCanvasDoubleClick(event: MouseEvent): void {
    if (this.selectedTool === 'polygon' || this.selectedTool === 'polyline') {
      const {x, y} = this.getCanvasCoords(event);
      this.finalizePolygon(this.drawingState.currentPoints);
      this.drawingState.isDrawing = false;
      this.render();
    }
  }

  // ===== Drawing Tools =====
  drawRectPreview(x1: number, y1: number, x2: number, y2: number): void {
    const color = this.getSelectedLabelColor();
    this.ctx.strokeStyle = color;
    this.ctx.lineWidth = 2 / this.zoomLevel;
    this.ctx.strokeRect(
      x1 * this.zoomLevel + this.panX,
      y1 * this.zoomLevel + this.panY,
      (x2 - x1) * this.zoomLevel,
      (y2 - y1) * this.zoomLevel
    );
  }

  drawPolygonPreview(points: Array<{x: number, y: number}>, currentX: number, currentY: number): void {
    if (points.length === 0) return;

    const color = this.getSelectedLabelColor();
    this.ctx.strokeStyle = color;
    this.ctx.lineWidth = 2 / this.zoomLevel;
    this.ctx.fillStyle = color + '33';

    const allPoints = [...points, {x: currentX, y: currentY}];
    this.ctx.beginPath();
    this.ctx.moveTo(
      allPoints[0].x * this.zoomLevel + this.panX,
      allPoints[0].y * this.zoomLevel + this.panY
    );
    for (let i = 1; i < allPoints.length; i++) {
      this.ctx.lineTo(
        allPoints[i].x * this.zoomLevel + this.panX,
        allPoints[i].y * this.zoomLevel + this.panY
      );
    }
    if (points.length > 2) {
      this.ctx.lineTo(
        points[0].x * this.zoomLevel + this.panX,
        points[0].y * this.zoomLevel + this.panY
      );
    }
    this.ctx.stroke();
  }

  drawBrush(x: number, y: number): void {
    const color = this.getSelectedLabelColor();
    this.ctx.fillStyle = color + (Math.round(this.brushOpacity * 255).toString(16).padStart(2, '0'));
    this.ctx.beginPath();
    this.ctx.arc(
      x * this.zoomLevel + this.panX,
      y * this.zoomLevel + this.panY,
      (this.brushSize / 2) * this.zoomLevel,
      0,
      Math.PI * 2
    );
    this.ctx.fill();
  }

  drawEraser(x: number, y: number): void {
    this.ctx.clearRect(
      (x - this.brushSize / 2) * this.zoomLevel + this.panX,
      (y - this.brushSize / 2) * this.zoomLevel + this.panY,
      (this.brushSize) * this.zoomLevel,
      (this.brushSize) * this.zoomLevel
    );
  }

  finalizeRect(x1: number, y1: number, x2: number, y2: number): void {
    if (Math.abs(x2 - x1) < 2 || Math.abs(y2 - y1) < 2) return; // Ignore tiny rectangles

    const annotation: AnnotationObject = {
      id: this.generateId(),
      type: 'rect',
      label: this.selectedLabel || 'unknown',
      points: [
        {x: Math.min(x1, x2), y: Math.min(y1, y2)},
        {x: Math.max(x1, x2), y: Math.max(y1, y2)}
      ],
      color: this.getSelectedLabelColor()
    };

    this.addAnnotationToHistory();
    this.annotations.push(annotation);
  }

  finalizePolygon(points: Array<{x: number, y: number}>): void {
    if (points.length < 3) return;

    const annotation: AnnotationObject = {
      id: this.generateId(),
      type: this.selectedTool as 'polygon' | 'polyline',
      label: this.selectedLabel || 'unknown',
      points: points,
      color: this.getSelectedLabelColor()
    };

    this.addAnnotationToHistory();
    this.annotations.push(annotation);
    this.drawingState.currentPoints = [];
  }

  addPoint(x: number, y: number): void {
    const annotation: AnnotationObject = {
      id: this.generateId(),
      type: 'point',
      label: this.selectedLabel || 'unknown',
      points: [{x, y}],
      color: this.getSelectedLabelColor()
    };

    this.addAnnotationToHistory();
    this.annotations.push(annotation);
  }

  // ===== Selection & Interaction =====
  selectAnnotationAtPoint(x: number, y: number): void {
    for (let i = this.annotations.length - 1; i >= 0; i--) {
      const ann = this.annotations[i];
      if (this.pointInAnnotation(x, y, ann)) {
        this.selectedAnnotationId = ann.id;
        return;
      }
    }
    this.selectedAnnotationId = null;
  }

  pointInAnnotation(x: number, y: number, ann: AnnotationObject): boolean {
    if (ann.type === 'rect' && ann.points.length === 2) {
      const [p1, p2] = ann.points;
      return x >= p1.x && x <= p2.x && y >= p1.y && y <= p2.y;
    } else if (ann.type === 'point') {
      return Math.hypot(x - ann.points[0].x, y - ann.points[0].y) < 10;
    } else if (ann.type === 'polygon') {
      return this.pointInPolygon(x, y, ann.points);
    }
    return false;
  }

  pointInPolygon(x: number, y: number, polygon: Array<{x: number, y: number}>): boolean {
    return this.drawingService.pointInPolygon(x, y, polygon);
  }

  deleteAnnotation(id: string): void {
    this.addAnnotationToHistory();
    this.annotations = this.annotations.filter(a => a.id !== id);
    this.selectedAnnotationId = null;
  }

  updateAnnotationLabel(id: string, label: string): void {
    const ann = this.annotations.find(a => a.id === id);
    if (ann) {
      this.addAnnotationToHistory();
      ann.label = label;
      ann.color = this.getColorForLabel(label);
    }
  }

  updateAnnotationAttribute(id: string, key: string, value: any): void {
    const ann = this.annotations.find(a => a.id === id);
    if (ann) {
      this.addAnnotationToHistory();
      if (!ann.attributes) ann.attributes = {};
      ann.attributes[key] = value;
    }
  }

  // ===== Rendering =====
  render = (): void => {
    if (!this.currentImage) return;

    // Clear canvas
    this.ctx.fillStyle = '#f5f5f5';
    this.ctx.fillRect(0, 0, this.canvas.width, this.canvas.height);

    // Save context state
    this.ctx.save();
    this.ctx.translate(this.panX, this.panY);
    this.ctx.scale(this.zoomLevel, this.zoomLevel);

    // Draw background image
    this.ctx.drawImage(this.currentImage, 0, 0);

    // Draw grid if enabled
    if (this.gridEnabled) {
      this.drawGrid();
    }

    // Draw annotations
    this.annotations.forEach((ann) => {
      const isSelected = ann.id === this.selectedAnnotationId;
      this.drawAnnotation(ann, isSelected);
    });

    this.ctx.restore();
  }

  drawGrid(spacing = 50): void {
    this.ctx.strokeStyle = '#ddd';
    this.ctx.lineWidth = 0.5;

    for (let x = 0; x < this.currentImage!.width; x += spacing) {
      this.ctx.beginPath();
      this.ctx.moveTo(x, 0);
      this.ctx.lineTo(x, this.currentImage!.height);
      this.ctx.stroke();
    }

    for (let y = 0; y < this.currentImage!.height; y += spacing) {
      this.ctx.beginPath();
      this.ctx.moveTo(0, y);
      this.ctx.lineTo(this.currentImage!.width, y);
      this.ctx.stroke();
    }
  }

  drawAnnotation(ann: AnnotationObject, isSelected: boolean): void {
    const color = ann.color;
    const strokeWidth = isSelected ? 3 : 2;

    this.ctx.strokeStyle = color;
    this.ctx.lineWidth = strokeWidth;
    this.ctx.fillStyle = color + '33';

    if (ann.type === 'rect') {
      const [p1, p2] = ann.points;
      this.ctx.fillRect(p1.x, p1.y, p2.x - p1.x, p2.y - p1.y);
      this.ctx.strokeRect(p1.x, p1.y, p2.x - p1.x, p2.y - p1.y);

      // Label
      this.drawLabel(ann.label, p1.x, p1.y - 5, color);

      // Selection handles
      if (isSelected) {
        this.drawSelectionHandles([p1, p2]);
      }
    } else if (ann.type === 'polygon' || ann.type === 'polyline') {
      this.ctx.beginPath();
      this.ctx.moveTo(ann.points[0].x, ann.points[0].y);
      for (let i = 1; i < ann.points.length; i++) {
        this.ctx.lineTo(ann.points[i].x, ann.points[i].y);
      }
      if (ann.type === 'polygon') {
        this.ctx.lineTo(ann.points[0].x, ann.points[0].y);
        this.ctx.fill();
      }
      this.ctx.stroke();

      if (isSelected && ann.points.length > 0) {
        this.drawSelectionHandles(ann.points);
      }

      this.drawLabel(ann.label, ann.points[0].x, ann.points[0].y - 5, color);
    } else if (ann.type === 'point') {
      const [p] = ann.points;
      this.ctx.fillStyle = color;
      this.ctx.beginPath();
      this.ctx.arc(p.x, p.y, 5, 0, Math.PI * 2);
      this.ctx.fill();
      this.ctx.stroke();

      this.drawLabel(ann.label, p.x + 10, p.y, color);
    }
  }

  drawLabel(text: string, x: number, y: number, color: string): void {
    this.ctx.font = 'bold 12px Arial';
    const metrics = this.ctx.measureText(text);
    const textWidth = metrics.width;
    const textHeight = 14;

    this.ctx.fillStyle = color;
    this.ctx.fillRect(x, y - textHeight, textWidth + 6, textHeight);

    this.ctx.fillStyle = 'white';
    this.ctx.fillText(text, x + 3, y - 2);
  }

  drawSelectionHandles(points: Array<{x: number, y: number}>): void {
    this.ctx.fillStyle = '#667eea';
    points.forEach(p => {
      this.ctx.fillRect(p.x - 4, p.y - 4, 8, 8);
    });
  }

  // ===== History =====
  addAnnotationToHistory(): void {
    this.history = this.history.slice(0, this.historyIndex + 1);
    this.history.push(JSON.parse(JSON.stringify(this.annotations)));
    this.historyIndex++;
  }

  undo(): void {
    if (this.historyIndex > 0) {
      this.historyIndex--;
      this.annotations = JSON.parse(JSON.stringify(this.history[this.historyIndex]));
      this.render();
    }
  }

  redo(): void {
    if (this.historyIndex < this.history.length - 1) {
      this.historyIndex++;
      this.annotations = JSON.parse(JSON.stringify(this.history[this.historyIndex]));
      this.render();
    }
  }

  cancelDrawing(): void {
    this.drawingState.isDrawing = false;
    this.drawingState.currentPoints = [];
    this.render();
  }

  // ===== File & Export =====
  uploadImage(): void {
    this.fileInput.nativeElement.click();
  }

  onFileSelected(event: Event): void {
    const input = event.target as HTMLInputElement;
    if (input.files) {
      this.files = Array.from(input.files);
      this.currentFileIndex = 0;
      this.loadFile(0);
    }
  }

  loadFile(index: number): void {
    if (index < 0 || index >= this.files.length) return;

    const file = this.files[index];
    const reader = new FileReader();

    reader.onload = (e) => {
      const img = new Image();
      img.onload = () => {
        this.currentImage = img;
        this.canvas.width = img.width;
        this.canvas.height = img.height;
        this.annotations = [];
        this.selectedAnnotationId = null;
        this.render();
      };
      img.src = e.target?.result as string;
    };

    reader.readAsDataURL(file);
  }

  nextFile(): void {
    if (this.currentFileIndex < this.files.length - 1) {
      this.currentFileIndex++;
      this.loadFile(this.currentFileIndex);
    }
  }

  previousFile(): void {
    if (this.currentFileIndex > 0) {
      this.currentFileIndex--;
      this.loadFile(this.currentFileIndex);
    }
  }

  exportAnnotations(format: 'coco' | 'voc' | 'yolo' | 'json'): void {
    const data = this.prepareExportData(format);
    const blob = new Blob([JSON.stringify(data, null, 2)], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `annotations.${format}.json`;
    a.click();
  }

  prepareExportData(format: string): any {
    // Convert annotations to specified format
    return {
      format: format,
      image: this.files[this.currentFileIndex]?.name,
      annotations: this.annotations
    };
  }

  saveAnnotations(): void {
    if (this.project) {
      const payload = {
        projectId: this.project.id,
        fileIndex: this.currentFileIndex,
        annotations: this.annotations
      };

      this.annotationService.createAnnotation(
        this.files[this.currentFileIndex]?.name || 'unknown',
        payload,
        '',
        this.project.id
      ).subscribe(() => {
        alert('Annotations saved successfully');
      });
    }
  }

  // ===== Utility =====
  setTool(tool: any): void {
    this.selectedTool = tool;
    this.cancelDrawing();
  }

  generateId(): string {
    return `${Date.now()}-${Math.random().toString(36).substr(2, 9)}`;
  }

  getSelectedLabelColor(): string {
    const label = this.labels.find(l => l.name === this.selectedLabel);
    return label?.color || '#667eea';
  }

  getColorForLabel(name: string): string {
    const label = this.labels.find(l => l.name === name);
    return label?.color || '#667eea';
  }

  toggleAttributesPanel(): void {
    this.showAttributesPanel = !this.showAttributesPanel;
  }

  toggleExportPanel(): void {
    this.showExportPanel = !this.showExportPanel;
  }

  toggleQualityFilter(): void {
    this.showQualityFilter = !this.showQualityFilter;
  }

  getSelectedAnnotation(): AnnotationObject | null {
    return this.annotations.find(a => a.id === this.selectedAnnotationId) || null;
  }
}
